+func (m *Model) cycleFocus(next bool) {
+	if next {
+		m.focusedPanel++
+		if m.focusedPanel >= numPanes {
+			m.focusedPanel = 0
+		}
+	} else {
+		m.focusedPanel--
+		if m.focusedPanel < 0 {
+			m.focusedPanel = numPanes - 1
+		}
+	}
+
+	// Update panel focus state
+	m.beadsPanel.Blur()
+	m.alertsPanel.Blur()
+
+	switch m.focusedPanel {
+	case PanelBeads:
+		m.beadsPanel.Focus()
+	case PanelAlerts:
+		m.alertsPanel.Focus()
+	}
+}
